const readme = $input.first().json.data || '';

const sectionMatch = readme.match(/## AI, ML, Big Data News([\s\S]*?)##/);
const section = sectionMatch ? sectionMatch[1] : readme;

const urls = [...section.matchAll(/\(RSS feed:\s*(https?:\/\/[^\)]+)\)/g)]
  .map(m => m[1].trim())
  .filter(url => url.length > 10);

console.log(`Total de feeds encontrados: ${urls.length}`);

return urls.map(url => ({ json: { rss_url: url } }));

const hoje = new Date().toISOString().split('T')[0];
const resultado = [];

for (const input of $input.all()) {
  const raw = input.json.data || input.json.body || '';
  if (!raw || typeof raw !== 'string') continue;

  // Extrai título do canal/feed
  const feedTitleMatch = raw.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i);
  const feedTitle = feedTitleMatch
    ? feedTitleMatch[1].replace(/<[^>]*>/g, '').trim()
    : 'RSS';

  // Extrai cada <item>
  const itens = [...raw.matchAll(/<item[^>]*>([\s\S]*?)<\/item>/gi)];

  for (const itemMatch of itens) {
    const bloco = itemMatch[1];

    const get = (tag) => {
      const m = bloco.match(
        new RegExp(`<${tag}[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/${tag}>`, 'i')
      );
      return m ? m[1].replace(/<[^>]*>/g, '').trim() : '';
    };

    const titulo = get('title');
    const url    = get('link') || get('guid');

    if (!titulo || titulo.length < 5) continue;

    resultado.push({ json: {
      titulo,
      url,
      resumo: (get('description') || get('summary') || get('content:encoded') || '').slice(0, 80),
      fonte:            feedTitle,
      autor:            get('dc:creator') || get('author') || '',
      data_publicacao:  get('pubDate') || get('dc:date') || new Date().toISOString(),
      data_coleta:      hoje,
      // campos a preencher pelo GPT
      pontuacao_relevancia: null,
      sentimento:           null,
      categoria:            null,
      oportunidade_startup: null
    }});
  }
}

console.log(`Artigos normalizados: ${resultado.length}`);
return resultado;

const itens = $input.all().map(i => i.json);

const palavrasAlta = [
  'gpt', 'llm', 'openai', 'anthropic', 'gemini', 'claude', 'mistral',
  'neural', 'deep learning', 'machine learning', 'artificial intelligence',
  'chatbot', 'transformer', 'diffusion', 'multimodal', 'agent',
  'benchmark', 'fine-tun', 'open source', 'language model'
];

const palavrasBaixa = [
  'deal', 'promo', 'unbox', 'hands-on', 'best buy',
  'discount', 'sale', 'coupon'
];

function pontuarLocalmente(item) {
  const texto = `${item.titulo} ${item.resumo}`.toLowerCase();
  let score = 0;
  palavrasAlta.forEach(p => { if (texto.includes(p)) score += 2; });
  palavrasBaixa.forEach(p => { if (texto.includes(p)) score -= 3; });
  if (item.fonte?.toLowerCase().includes('arxiv')) score += 4;
  if (item.fonte?.toLowerCase().includes('github')) score += 2;
  if ((item.resumo || '').length < 50) score -= 1;
  return score;
}

const urlsVistas = new Set();
const titulosVistos = [];

function similaridade(a, b) {
  const pa = new Set(a.toLowerCase().split(/\s+/));
  const pb = b.toLowerCase().split(/\s+/);
  const comuns = pb.filter(p => pa.has(p)).length;
  return comuns / Math.max(pa.size, pb.length);
}

const resultado = [];
for (const item of itens) {
  if (item.url && urlsVistas.has(item.url)) continue;
  if (titulosVistos.some(t => similaridade(t, item.titulo) > 0.75)) continue;
  if (item.url) urlsVistas.add(item.url);
  titulosVistos.push(item.titulo);
  resultado.push(item);
}

return resultado
  .map(item => ({ ...item, score_local: pontuarLocalmente(item) }))
  .sort((a, b) => b.score_local - a.score_local)
  .slice(0, 10)
  .map(item => ({ json: item }));

return $input.all().map(item => {
  const j = item.json;

  // Tenta todos os caminhos possíveis
  const text = (
    j?.content?.[0]?.text ||
    j?.message?.content ||
    j?.choices?.[0]?.message?.content ||
    j?.text ||
    j?.output?.[0]?.content?.[0]?.text ||
    ''
  ).replace(/`/g, '').trim();

  if (!text) return { json: { _erro: 'texto vazio', _keys: JSON.stringify(Object.keys(j)) } };

  try {
    return { json: JSON.parse(text) };
  } catch(e) {
    return { json: { _erro: e.message, _texto: text.slice(0, 200) } };
  }
});

const itens = $input.all().map(i => i.json);
const hoje = new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

// Top 5 artigos por relevância
const top5 = [...itens]
  .sort((a, b) => (b.pontuacao_relevancia || 0) - (a.pontuacao_relevancia || 0))
  .slice(0, 5);

// Contagem por categoria
const porCategoria = {};
itens.forEach(i => {
  const cat = i.categoria || 'Outros';
  porCategoria[cat] = (porCategoria[cat] || 0) + 1;
});

// Contagem de sentimentos
const sentimentos = { positivo: 0, neutro: 0, negativo: 0 };
itens.forEach(i => {
  const s = i.sentimento || 'neutro';
  if (sentimentos[s] !== undefined) sentimentos[s]++;
});

// Artigos com oportunidade de startup
const comOportunidade = itens.filter(i => i.oportunidade_startup && i.oportunidade_startup !== 'null');

// Sentimento dominante
const sentimentoDominante = Object.entries(sentimentos)
  .sort((a, b) => b[1] - a[1])[0][0];

const emojiSentimento = { positivo: '🟢', neutro: '🟡', negativo: '🔴' };

return [{
  json: {
    data: hoje,
    total_artigos: itens.length,
    top5,
    por_categoria: porCategoria,
    sentimentos,
    sentimento_dominante: sentimentoDominante,
    emoji_sentimento: emojiSentimento[sentimentoDominante] || '🟡',
    oportunidades_startup: comOportunidade.slice(0, 3),
    total_oportunidades: comOportunidade.length
  }
}];

const d = $input.first().json;

const top5 = (d.top5 || []).map((a, i) => 
  `${i+1}. [${a.pontuacao_relevancia}/10] *${(a.titulo || '').slice(0, 80)}*
   📌 ${a.categoria} | ${a.fonte}
   🔗 ${a.url}`
).join('

');

const oportunidades = (d.oportunidades_startup || []).length > 0
  ? d.oportunidades_startup.map(o => 
      `• *${(o.titulo || '').slice(0, 60)}...*
  💼 ${o.oportunidade_startup}`
    ).join('
')
  : 'Nenhuma identificada hoje.';

const categorias = Object.entries(d.por_categoria || {})
  .map(([k, v]) => `• ${k}: ${v}`)
  .join('
');

return [{
  json: {
    mensagem: `🤖 *Inteli AI Intelligence Hub — Coleta Diária*
📅 ${d.data}

${d.emoji_sentimento} *Sentimento geral:* ${d.sentimento_dominante} | 📰 *${d.total_artigos} artigos* coletados

---

🏆 *TOP 5 ARTIGOS DO DIA:*
${top5}

---

💡 *${d.total_oportunidades} OPORTUNIDADE(S) DE STARTUP:*
${oportunidades}

---

📊 *POR CATEGORIA:*
${categorias}

_Próximo passo: Workflow 2 roda todo domingo_ 🗓️`
  }
}];
